class Solution {
public:
    int numberOfWays(int n, int x, int y) {
        const int MOD = 1e9 + 7;
        vector<vector<long long>> dp(n + 1, vector<long long>(x, 0));
        for (int i = 0; i < x; ++i) {
            dp[0][i] = 1;
        }
        for (int i = 1; i <= n; ++i) {
            for (int j = 0; j < x; ++j) {
                dp[i][j] = (dp[i][j] + dp[i - 1][j] * (j + 1)) % MOD;
                if (j > 0) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - 1] * (x - j + 1)) % MOD;
                }
            }
        }
        long long total_ways = 0;
        for (int i = 0; i < x; ++i) {
            total_ways = (total_ways + dp[n][i]) % MOD;
        }
        total_ways = (total_ways * power(y, x, MOD)) % MOD;
        return total_ways;
    }

    long long power(long long base, long long exponent, long long mod) {
        long long result = 1;
        while (exponent > 0) {
            if (exponent % 2 == 1) {
                result = (result * base) % mod;
            }
            base = (base * base) % mod;
            exponent /= 2;
        }
        return result;
    }
};
